INSERT INTO pacs_results ( hospital_id, modality_id, study_id, worklist_id, patient_id, result_date, template_id, result_text, status, completed, is_active, created_by, created_at, modified_at ) VALUES ( #{request.hospitalId}, #{request.modalityId}, #{request.studyId}, #{request.worklistId}, #{request.patientId}, COALESCE(#{request.resultDate}, CURRENT_DATE), #{request.templateId}, #{request.resultText}, #{status}, COALESCE(#{request.completed}, FALSE), 1, #{createdBy}, NOW(), NOW() )
ON CONFLICT (hospital_id, study_id) WHERE is_active = 1 AND study_id IS NOT NULL DO UPDATE SET worklist_id = COALESCE(EXCLUDED.worklist_id, pacs_results.worklist_id), patient_id = COALESCE(EXCLUDED.patient_id, pacs_results.patient_id), result_date = EXCLUDED.result_date, template_id = EXCLUDED.template_id, result_text = EXCLUDED.result_text, status = EXCLUDED.status, completed = EXCLUDED.completed, modified_at = NOW() WHERE pacs_results.created_by IS NULL OR pacs_results.created_by = #{createdBy}
ON CONFLICT (hospital_id, worklist_id) WHERE is_active = 1 AND worklist_id IS NOT NULL DO UPDATE SET study_id = COALESCE(EXCLUDED.study_id, pacs_results.study_id), patient_id = COALESCE(EXCLUDED.patient_id, pacs_results.patient_id), result_date = EXCLUDED.result_date, template_id = EXCLUDED.template_id, result_text = EXCLUDED.result_text, status = EXCLUDED.status, completed = EXCLUDED.completed, modified_at = NOW() WHERE pacs_results.created_by IS NULL OR pacs_results.created_by = #{createdBy}
RETURNING id

