UPDATE pacs_results SET hospital_id = #{request.hospitalId}, modality_id = #{request.modalityId}, study_id = #{request.studyId}, worklist_id = #{request.worklistId}, patient_id = #{request.patientId}, result_date = COALESCE(#{request.resultDate}, result_date, CURRENT_DATE), template_id = #{request.templateId}, result_text = #{request.resultText}, status = #{status}, completed = COALESCE(#{request.completed}, FALSE), modified_at = NOW() WHERE is_active = 1
AND result_public_id = CAST(#{request.resultKey} AS uuid)
AND id = #{request.id}

