SELECT

FROM pacs_results pr

LEFT JOIN pacs_result_templates rt ON rt.id = pr.template_id
WHERE pr.hospital_id = #{hospitalId}
  AND pr.modality_id = #{modalityId}
  AND pr.is_active = 1
  AND pr.study_id = #{studyId}
ORDER BY pr.id DESC
LIMIT 1

SELECT

FROM pacs_results pr

LEFT JOIN pacs_result_templates rt ON rt.id = pr.template_id
WHERE pr.hospital_id = #{hospitalId}
  AND pr.modality_id = #{modalityId}
  AND s.study_instance_uid = #{studyInstanceUid}
  AND pr.is_active = 1
ORDER BY pr.id DESC
LIMIT 1

SELECT
FROM pacs_worklists q INNER JOIN hospitals h ON h.id = q.hospital_id INNER JOIN patients p ON p.id = q.patient_id AND p.hospital_id = q.hospital_id LEFT JOIN pacs_worklist_study_links qsl ON qsl.hospital_id = q.hospital_id AND qsl.worklist_id = q.id AND qsl.is_primary = 1 LEFT JOIN pacs_studies s ON s.hospital_id = q.hospital_id AND s.id = COALESCE(q.study_id, qsl.study_id) AND s.is_active = 1 LEFT JOIN modalities m ON m.id = q.modality_id AND m.is_active = 1 WHERE q.id = #{request.worklistId}
AND q.hospital_id = #{request.hospitalId}
LIMIT 1

SELECT
FROM pacs_studies s INNER JOIN hospitals h ON h.id = s.hospital_id INNER JOIN patients p ON p.id = s.patient_id AND p.hospital_id = s.hospital_id LEFT JOIN pacs_worklist_study_links qsl ON qsl.hospital_id = s.hospital_id AND qsl.study_id = s.id AND qsl.is_primary = 1 LEFT JOIN pacs_worklists q ON q.id = qsl.worklist_id AND q.hospital_id = s.hospital_id LEFT JOIN modalities m ON m.is_active = 1 AND ( m.id = q.modality_id OR ( q.modality_id IS NULL AND ( UPPER(COALESCE(m.abbr, '')) = UPPER(COALESCE(s.modality, '')) OR UPPER(COALESCE(m.name, '')) = UPPER(COALESCE(s.modality, '')) ) ) ) LEFT JOIN hospital_modalities hm ON hm.hospital_id = s.hospital_id AND hm.modality_id = m.id AND hm.is_active = 1 WHERE s.id = #{request.studyId} AND s.is_active = 1
AND s.hospital_id = #{request.hospitalId}
AND COALESCE(q.modality_id, m.id) = #{request.modalityId}
AND (q.modality_id IS NOT NULL OR hm.modality_id IS NOT NULL) ORDER BY q.id DESC NULLS LAST, s.id DESC LIMIT 1

SELECT
FROM pacs_studies s INNER JOIN hospitals h ON h.id = s.hospital_id INNER JOIN patients p ON p.id = s.patient_id AND p.hospital_id = s.hospital_id LEFT JOIN pacs_worklist_study_links qsl ON qsl.hospital_id = s.hospital_id AND qsl.study_id = s.id AND qsl.is_primary = 1 LEFT JOIN pacs_worklists q ON q.id = qsl.worklist_id AND q.hospital_id = s.hospital_id LEFT JOIN modalities m ON m.is_active = 1 AND ( m.id = q.modality_id OR ( q.modality_id IS NULL AND ( UPPER(COALESCE(m.abbr, '')) = UPPER(COALESCE(s.modality, '')) OR UPPER(COALESCE(m.name, '')) = UPPER(COALESCE(s.modality, '')) ) ) ) LEFT JOIN hospital_modalities hm ON hm.hospital_id = s.hospital_id AND hm.modality_id = m.id AND hm.is_active = 1 WHERE s.study_instance_uid = #{request.studyInstanceUid} AND s.is_active = 1
AND s.hospital_id = #{request.hospitalId}
AND COALESCE(q.modality_id, m.id) = #{request.modalityId}
AND (q.modality_id IS NOT NULL OR hm.modality_id IS NOT NULL) ORDER BY q.id DESC NULLS LAST, s.id DESC LIMIT 1

SELECT
FROM pacs_worklists q INNER JOIN hospitals h ON h.id = q.hospital_id INNER JOIN patients p ON p.id = q.patient_id AND p.hospital_id = q.hospital_id LEFT JOIN pacs_worklist_study_links qsl ON qsl.hospital_id = q.hospital_id AND qsl.worklist_id = q.id AND qsl.is_primary = 1 LEFT JOIN pacs_studies s ON s.hospital_id = q.hospital_id AND s.id = COALESCE(q.study_id, qsl.study_id) AND s.is_active = 1 LEFT JOIN modalities m ON m.id = q.modality_id AND m.is_active = 1 WHERE ( q.visit_code = #{request.accessionNumber} OR s.accession_number = #{request.accessionNumber} )
AND q.hospital_id = #{request.hospitalId}
AND q.modality_id = #{request.modalityId}
ORDER BY q.id DESC LIMIT 1

SELECT

FROM pacs_results pr

LEFT JOIN pacs_result_templates rt ON rt.id = pr.template_id
WHERE pr.hospital_id = #{request.hospitalId}
  AND pr.modality_id = #{request.modalityId}
  AND pr.is_active = 1


        AND (


                OR pr.study_id = #{request.studyId}


                OR pr.worklist_id = #{request.worklistId}


                OR s.study_instance_uid = #{request.studyInstanceUid}


                OR COALESCE(s.accession_number, q.visit_code) = #{request.accessionNumber}


        )


        AND 1 = 0


ORDER BY pr.id DESC
LIMIT 1

