SELECT

FROM pacs_viewer_states pvs
INNER JOIN hospitals h ON h.id = pvs.hospital_id
LEFT JOIN modalities m ON m.id = pvs.modality_id
LEFT JOIN pacs_studies s ON s.id = pvs.study_id AND s.hospital_id = pvs.hospital_id
LEFT JOIN pacs_worklists q ON q.id = pvs.worklist_id AND q.hospital_id = pvs.hospital_id
LEFT JOIN patients p ON p.id = pvs.patient_id AND p.hospital_id = pvs.hospital_id
WHERE pvs.is_active = 1
  AND pvs.hospital_id = #{request.hospitalId}
  AND pvs.state_type = #{request.stateType}


        AND pvs.public_id = CAST(#{request.viewerStateKey} AS uuid)


        AND pvs.worklist_id = #{request.worklistId}


        AND pvs.study_id = #{request.studyId}


        AND pvs.study_instance_uid = #{request.studyInstanceUid}


        AND pvs.accession_number = #{request.accessionNumber}


ORDER BY pvs.modified_at DESC, pvs.id DESC
LIMIT 1

SELECT

FROM pacs_viewer_states pvs
INNER JOIN hospitals h ON h.id = pvs.hospital_id
LEFT JOIN modalities m ON m.id = pvs.modality_id
LEFT JOIN pacs_studies s ON s.id = pvs.study_id AND s.hospital_id = pvs.hospital_id
LEFT JOIN pacs_worklists q ON q.id = pvs.worklist_id AND q.hospital_id = pvs.hospital_id
LEFT JOIN patients p ON p.id = pvs.patient_id AND p.hospital_id = pvs.hospital_id
WHERE pvs.is_active = 1
  AND pvs.hospital_id = #{request.hospitalId}
  AND pvs.state_type = #{request.stateType}


        AND pvs.public_id = CAST(#{request.viewerStateKey} AS uuid)


        AND pvs.worklist_id = #{request.worklistId}


        AND pvs.study_id = #{request.studyId}


        AND pvs.study_instance_uid = #{request.studyInstanceUid}


        AND pvs.accession_number = #{request.accessionNumber}


ORDER BY pvs.modified_at DESC, pvs.id DESC
LIMIT 1

SELECT 1
FROM (
    SELECT pg_advisory_xact_lock(
        hashtextextended(
            CONCAT_WS(
                '|',
                #{request.hospitalId}::text,
                #{request.stateType},


                        'worklist:' || #{request.worklistId}::text


                        'study:' || #{request.studyId}::text


                        'study-uid:' || #{request.studyInstanceUid}


                        'accession:' || #{request.accessionNumber}


            ),
            0
        )
    )
) viewer_state_scope_lock

mapper.update:
UPDATE pacs_viewer_states
SET
    modality_id = #{request.modalityId},
    study_id = #{request.studyId},
    worklist_id = #{request.worklistId},
    patient_id = #{request.patientId},
    study_instance_uid = #{request.studyInstanceUid},
    accession_number = #{request.accessionNumber},
    patient_code = #{request.patientCode},
    schema_version = #{request.schemaVersion},
    viewer_state = CAST(#{request.viewerStateJson} AS jsonb),
    measurements = CAST(#{request.measurementsJson} AS jsonb),
    annotations = CAST(#{request.annotationsJson} AS jsonb),
    segmentations = CAST(#{request.segmentationsJson} AS jsonb),
    labelmap_segmentations = CAST(#{request.labelmapSegmentationsJson} AS jsonb),
    contour_segmentations = CAST(#{request.contourSegmentationsJson} AS jsonb),
    surface_segmentations = CAST(#{request.surfaceSegmentationsJson} AS jsonb),
    additional_findings = CAST(#{request.additionalFindingsJson} AS jsonb),
    presentation_state = CAST(#{request.presentationStateJson} AS jsonb),
    tool_state = CAST(#{request.toolStateJson} AS jsonb),
    metadata = CAST(#{request.metadataJson} AS jsonb),
    payload_size_bytes = #{request.payloadSizeBytes},
    payload_sha256 = #{request.payloadSha256},
    version = version + 1,
    modified_by = #{modifiedBy},
    modified_at = NOW()
WHERE id = #{request.id}
  AND hospital_id = #{request.hospitalId}
  AND is_active = 1
  AND (
      payload_sha256 IS DISTINCT FROM #{request.payloadSha256}
      OR modality_id IS DISTINCT FROM #{request.modalityId}
      OR study_id IS DISTINCT FROM #{request.studyId}
      OR worklist_id IS DISTINCT FROM #{request.worklistId}
      OR patient_id IS DISTINCT FROM #{request.patientId}
      OR study_instance_uid IS DISTINCT FROM #{request.studyInstanceUid}
      OR accession_number IS DISTINCT FROM #{request.accessionNumber}
      OR patient_code IS DISTINCT FROM #{request.patientCode}
      OR schema_version IS DISTINCT FROM #{request.schemaVersion}
  )

UPDATE pacs_viewer_states SET is_active = 2, viewer_state = '{}'::jsonb, measurements = '[]'::jsonb, annotations = '[]'::jsonb, segmentations = '[]'::jsonb, labelmap_segmentations = '[]'::jsonb, contour_segmentations = '[]'::jsonb, surface_segmentations = '[]'::jsonb, additional_findings = '[]'::jsonb, presentation_state = '{}'::jsonb, tool_state = '{}'::jsonb, metadata = jsonb_build_object('deleted', true), payload_size_bytes = 0, payload_sha256 = NULL, deleted_by = #{modifiedBy}, deleted_at = NOW(), modified_by = #{modifiedBy}, modified_at = NOW() WHERE is_active = 1 AND hospital_id = #{request.hospitalId} AND state_type = #{request.stateType}
AND public_id = CAST(#{request.viewerStateKey} AS uuid)
AND worklist_id = #{request.worklistId}
AND study_id = #{request.studyId}
AND study_instance_uid = #{request.studyInstanceUid}
AND accession_number = #{request.accessionNumber}
